import{_ as o,o as r,c as t,a3 as a}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"95. Working From Home","description":"","frontmatter":{"title":"95. Working From Home","eba":"Allied Health Professionals 2021-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/allied-health/workplace-rights/95-working-from-home.md","filePath":"ebas/allied-health/workplace-rights/95-working-from-home.md"}'),n={name:"ebas/allied-health/workplace-rights/95-working-from-home.md"};function i(s,e,l,m,h,p){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="_95-working-from-home" tabindex="-1">95. Working From Home <a class="header-anchor" href="#_95-working-from-home" aria-label="Permalink to &quot;95. Working From Home&quot;">​</a></h1><p><strong>95.1</strong> The Employer recognises there may be mutual benefits for both Employees and the Employer to access home based work. The Employer will maintain a working from home policy that provides Employees with a genuine opportunity to work from home where it is reasonable having regard for the circumstances, including:</p><p><strong>(a)</strong> OHS considerations;</p><p><strong>(b)</strong> any current Government directives or recommendations;</p><p><strong>(c)</strong> service delivery requirements.</p><p><strong>95.2</strong> An Employee is entitled to make a request to work from home in accordance with the Employer’s policy.</p><p><strong>95.3</strong> Where an application is made in accordance with the Employer’s policy such a request will not be unreasonably refused by the Employer.</p><p><strong>95.4</strong> Nothing in this clause 95 limits the right of an Employee to request a flexible working arrangement under <a href="/eba/ebas/allied-health/workplace-rights/96-flexible-working-arrangements.html">clause 96</a> of this Agreement.</p>',8)])])}const d=o(n,[["render",i]]);export{g as __pageData,d as default};
